def normalize(text: str) -> str:
    return re.sub(r"\s+", " ", text.lower()).strip()


def score_card(question: str, card: Card) -> int:
    score = 0
    for keyword in card.keywords:
        if keyword in question:
            score += 2 if " " in keyword else 1
    return score


def find_card(question: str) -> tuple[Card | None, int]:
    scores = [(score_card(question, card), card) for card in CARDS]
    scores.sort(key=lambda item: item[0], reverse=True)
    best_score, best_card = scores[0]
    if best_score <= 0:
        return None, 0
    return best_card, best_score


def confidence(score: int, handoff: bool) -> str:
    if handoff:
        return "╨╜╨╕╨╖╨║╨░╤П"
    if score >= 3:
        return "╨▓╤Л╤Б╨╛╨║╨░╤П"
    if score >= 1:
        return "╤Б╤А╨╡╨┤╨╜╤П╤П"
    return "╨╜╨╕╨╖╨║╨░╤П"


