        print('python3 scripts/support_lookup.py "╨╝╨╛╨╢╨╜╨╛ ╨▒╨╡╤А╨╡╨╝╨╡╨╜╨╜╤Л╨╝ ╤Н╤В╨╛╤В ╨║╤А╨╡╨╝"')
